const cellKey = ([row, col]: Cell): string => `${row},${col}`;

const parseKey = (key: string): Cell => {
  const [r, c] = key.split(",").map(Number);
  return [r, c];
};

const isNeighbor = ([row, col]: Cell, [otherRow, otherCol]: Cell): boolean =>
  !(otherRow === row && otherCol === col) &&
  Math.abs(otherRow - row) <= 1 &&
  Math.abs(otherCol - col) <= 1;

const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter((other) => isNeighbor(cell, other)).length;

const deadNeighbors = (liveCells: Cell[]): Cell[] => {
  const liveSet = new Set(liveCells.map(cellKey));
  const candidates = new Set<string>();
  for (const [row, col] of liveCells) {
    for (let dr = -1; dr <= 1; dr++) {
      for (let dc = -1; dc <= 1; dc++) {
        if (dr === 0 && dc === 0) continue;
        const key = cellKey([row + dr, col + dc]);
        if (!liveSet.has(key)) candidates.add(key);
      }
    }
  }
  return [...candidates].map(parseKey);
};

